#!/usr/bin/env python3
"""Block `pnpm test` (interactive watcher); steer Claude to `pnpm test:ci`."""
import json, sys

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name") != "Bash":
        return 0
    cmd = (ev.get("tool_input") or {}).get("command", "")
    if cmd.strip().startswith("pnpm test") and "test:ci" not in cmd:
        print("Use `pnpm test:ci` instead — `pnpm test` opens an interactive watcher and won't return.", file=sys.stderr)
        return 2
    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""Warn after Edit if code introduces recursive calls without obvious bounds."""
import ast, json, sys, os

def has_base_case(func_def):
    """Naive heuristic: if-statement with early return suggests base case."""
    for node in ast.walk(func_def):
        if isinstance(node, ast.If):
            for child in ast.walk(node):
                if isinstance(child, ast.Return):
                    return True
    return False

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    if tool not in ("Edit", "MultiEdit"):
        return 0

    inp = ev.get("tool_input") or {}
    file_path = inp.get("file_path", "")

    if not file_path.endswith(".py"):
        return 0

    if not os.path.exists(file_path):
        return 0

    try:
        with open(file_path, 'r') as f:
            code = f.read()
        tree = ast.parse(code)
    except Exception:
        return 0

    warnings = []
    for node in ast.walk(tree):
        if isinstance(node, ast.FunctionDef):
            func_name = node.name
            calls_self = False
            for child in ast.walk(node):
                if isinstance(child, ast.Call):
                    if isinstance(child.func, ast.Name) and child.func.id == func_name:
                        calls_self = True
                        break
            if calls_self and not has_base_case(node):
                warnings.append(func_name)

    if warnings:
        print(f"Recursion without obvious base case detected in {file_path}:", file=sys.stderr)
        for fn in warnings:
            print(f"  {fn}()", file=sys.stderr)
        print("Consider: iterative approach, depth limit, or explicit base case.", file=sys.stderr)
        return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""After pytest runs, detect RecursionError and surface specific guidance."""
import json, sys

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    if ev.get("tool_name") != "Bash":
        return 0

    inp = ev.get("tool_input") or {}
    cmd = inp.get("command", "")

    if "pytest" not in cmd and "python -m pytest" not in cmd:
        return 0

    resp = ev.get("tool_response") or {}
    stderr = resp.get("stderr", "")
    stdout = resp.get("stdout", "")

    if "RecursionError" in stderr or "RecursionError" in stdout:
        print("RecursionError detected in test output.", file=sys.stderr)
        print("Likely unbounded recursion - consider iterative approach or depth limit.", file=sys.stderr)
        return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""Auto-format Python files after Write/Edit using ruff format."""
import json, subprocess, sys, os

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    if ev.get("tool_name") not in ("Write", "Edit"):
        return 0

    inp = ev.get("tool_input") or {}
    file_path = inp.get("file_path", "")

    if not file_path.endswith(".py"):
        return 0

    if not os.path.isfile(file_path):
        return 0

    try:
        subprocess.run(
            ["ruff", "format", file_path],
            capture_output=True,
            timeout=10
        )
    except Exception:
        pass

    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""After Edit/MultiEdit on a line that defines an exported identifier, grep
for references and feed the list back to Claude so it can verify consistency."""
import json, re, subprocess, sys

EXPORT_DEF = re.compile(
    r"export\s+(?:const|let|var|function|class|type|interface|enum)\s+(\w+)"
)

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name") not in ("Edit", "MultiEdit"):
        return 0
    inp = ev.get("tool_input") or {}
    edits = inp.get("edits") or [
        {"old_string": inp.get("old_string", ""), "new_string": inp.get("new_string", "")}
    ]

    names: set[str] = set()
    for e in edits:
        for s in (e.get("old_string", ""), e.get("new_string", "")):
            m = EXPORT_DEF.search(s)
            if m:
                names.add(m.group(1))

    if not names:
        return 0

    for name in names:
        try:
            r = subprocess.run(
                ["grep", "-rn", "--include=*.ts", "--include=*.tsx",
                 "--include=*.js", "--include=*.jsx", name, "."],
                capture_output=True, text=True, timeout=5, cwd=ev.get("cwd", ".")
            )
            hits = [l for l in r.stdout.splitlines() if l][:20]
            if hits:
                print(f"Export `{name}` touched. References in codebase:", file=sys.stderr)
                for h in hits:
                    print(f"  {h}", file=sys.stderr)
                print("Verify these are consistent with your change.", file=sys.stderr)
                return 2
        except Exception:
            pass
    return 0

if __name__ == "__main__":
    sys.exit(main())
